import{c as e,cG as t,cb as a,c8 as r,cf as i,cT as n,ce as o}from"./chunks/framework.BlkIsu1j.js";const s=JSON.parse('{"title":"Type Manipulation","description":"","frontmatter":{"title":"Type Manipulation","outline":"deep","layout":"doc","prev":true,"next":true,"sidebar":true,"date":"2025-07-10T10:44:56.000Z"},"headers":[],"relativePath":"lang/typescript/06 Type Manipulation.md","filePath":"lang/typescript/06 Type Manipulation.md","lastUpdated":1755614503000}'),l={id:"frontmatter-title",tabindex:"-1"};const p=e({name:"lang/typescript/06 Type Manipulation.md"},[["render",function(e,s,p,c,d,y){return t(),a("div",null,[r("h1",l,[i(n(e.$frontmatter.title)+" ",1),s[0]||(s[0]=r("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),s[1]||(s[1]=o('<h2 id="用类型创建类型" tabindex="-1">用类型创建类型 <a class="header-anchor" href="#用类型创建类型" aria-label="Permalink to “用类型创建类型”">​</a></h2><p>TypeScript 的类型系统非常强大，因为它允许<em>用其他类型来</em>表达类型。</p><p>这种想法最简单的形式就是泛型。此外，我们还有各种各样的类型<em>运算符</em>可供使用。我们也可以用已有的<em>值来表达类型。</em></p><p>通过组合各种类型运算符，我们可以用简洁、易维护的方式表达复杂的运算和值</p><ul><li><strong>Generics</strong> - 接受参数的类型</li><li><strong>Keyof Type Operator</strong> - 使用 <code>keyof</code> 来创建新类型</li><li><strong>Typeof Type Operator</strong> - 使用 <code>typeof</code> 来创建新类型</li><li><strong>Indexed Access Types</strong> - 使用 <code>Type[&#39;a&#39;]</code> 语法来访问类型的子集syntax to access a subset of a type</li><li><strong>Conditional Types</strong> - 在类型系统中表现得像 if 语句的类型</li><li><strong>Mapped Types</strong> - 通过映射现有类型中的每个属性来创建类型</li><li><strong>Template Literal Types</strong> - 通过模板文字字符串改变属性的映射类型</li></ul>',5))])}]]);export{s as __pageData,p as default};
